package api

import (
	"io"
	"strings"
	"testing"

	"github.com/stretchr/testify/assert"

	"github.com/DataDog/datadog-saist/internal/model/api"
)

func TestGetPromptsFromApi(t *testing.T) {
	auth, err := GetDatadogAuth()
	assert.NoError(t, err)

	if auth.ApiKey == nil || auth.AppKey == nil {
		t.Skip("Skipping test: DD_API_KEY or DD_APP_KEY not set")
	}

	prompts, err := GetPromptsFromApi(t.Context(), auth)
	assert.NoError(t, err)
	assert.NotNil(t, prompts)
	assert.True(t, len(prompts) > 0)
}

func TestGetPromptsFromApiData(t *testing.T) {
	jsonData := `{
		"data": [
			{
				"id": "datadog/java-sqli",
				"type": "ai_prompt",
				"attributes": {
					"category": "SECURITY",
					"checksum": "178c866efad9b35055fe03eb02cc4a58",
					"content": "",
					"cwe": "89",
					"directories": [],
					"execution_mode": "ALWAYS",
					"globs": [
						"**/*.java"
					],
					"is_default": true,
					"is_testing": false,
					"severity": "WARNING"
				}
			}
		]
	}`

	reader := io.NopCloser(strings.NewReader(jsonData))

	prompts, err := GetPromptsFromApiData(reader)

	assert.NoError(t, err)
	assert.Len(t, prompts, 1)

	prompt := prompts[0]
	assert.Equal(t, "datadog/java-sqli", prompt.ID)
	assert.Equal(t, api.CategorySecurity, prompt.Category)
	assert.Equal(t, "178c866efad9b35055fe03eb02cc4a58", prompt.Checksum)
	assert.Equal(t, "89", *prompt.Cwe)
	assert.Empty(t, prompt.Directories)
	assert.Equal(t, api.ExecutionModeAlways, prompt.ExecutionMode)
	assert.Equal(t, []string{"**/*.java"}, prompt.Globs)
	assert.True(t, prompt.IsDefault)
	assert.False(t, prompt.IsTesting)
	assert.Equal(t, api.SeverityWarning, prompt.Severity)

	expectedContentStart := "Evaluate the following code located in <path>:"
	assert.Contains(t, prompt.Content, expectedContentStart)
	assert.Contains(t, prompt.Content, "SQL injections")
	assert.Contains(t, prompt.Content, "NO VIOLATION AMIGO")
}
